const data = ($input.first().json?.data || $input.first().json) || {};

const claimId = data.claimNumber || `CLM-${Date.now().toString(36).toUpperCase()}`;
const totalAmount  = parseFloat(data.totalAmount)  || 0;
const deductible   = parseFloat(data.deductible)   || 0;
const copay        = parseFloat(data.coPayment)     || 0;
const estimatedReimbursement = Math.max(0, totalAmount - deductible - copay);

let routeTo = 'Auto-Approve';
if (totalAmount > 5000)      routeTo = 'Senior Adjuster';
else if (totalAmount >= 1000) routeTo = 'Claims Adjuster';

const flags = [];
if (!data.preAuthNumber && totalAmount > 500) flags.push('Missing Pre-Authorization');
if (!data.supportingDocsList || data.supportingDocsList === 'None' || data.supportingDocsList === '') {
  flags.push('No Supporting Documents');
}

return [{ json: {
  claimId,
  claimType:               data.claimType               || 'Other',
  policyNumber:            data.policyNumber            || 'N/A',
  claimantName:            data.claimantName            || 'N/A',
  incidentDate:            data.incidentDate            || 'N/A',
  incidentDescription:     data.incidentDescription     || 'N/A',
  providerName:            data.providerName            || 'N/A',
  diagnosisList:           data.diagnosisList           || 'N/A',
  proceduresList:          data.proceduresList          || 'N/A',
  totalAmount,
  deductible,
  estimatedReimbursement,
  routeTo,
  flags:     flags.join(', ') || 'None',
  flagCount: flags.length,
  processedAt: new Date().toISOString()
}}];

